const body = $json.body || $json;
const required = ['request_id', 'workflow_type', 'generated_by', 'client', 'brand', 'campaign', 'brief', 'options', 'ads_pack_types', 'safety'];
const missing = required.filter((key) => body[key] === undefined || body[key] === null);
const safety = body.safety || {};
const safetyOk = body.workflow_type === 'ads_pack'
  && body.owner_approval_required === true
  && body.generate_images === false
  && body.generate_videos === false
  && body.create_ads === false
  && body.launch_ads === false
  && safety.no_auto_post === true
  && safety.no_auto_ads === true
  && safety.no_live_connectors === true
  && safety.no_platform_launch === true
  && safety.no_image_generation === true
  && safety.no_video_generation === true
  && safety.no_secrets === true
  && safety.owner_approval_required === true;
if (missing.length || !safetyOk) {
  return [{ json: {
    ok: false,
    request_id: body.request_id || null,
    error: {
      code: missing.length ? 'INVALID_CONTRACT' : 'REJECTED_BY_SAFETY',
      message: missing.length ? `Missing required fields: ${missing.join(', ')}` : 'Safety flags rejected this request (ads pack is strategy/draft notes only — no ads are created, launched, scheduled, or spent, and no image or video generation).'
    },
    status: 'failed',
    owner_approval_required: true,
    safety
  }}];
}
return [{ json: body }];

const request = $json;
const channel = request.options?.channel || 'Facebook';
const goal = request.options?.goal || 'branding';
const brand = request.brand?.name || 'Brand';
const product = request.brief?.product_focus || request.brand?.hero_product || 'hero product';
const audience = request.brief?.target_audience || request.brand?.target_audience || 'core local audience';
const offer = request.brief?.offer || 'Assumption: feature the current campaign hero offer';
const cta = goal === 'sales' ? 'Inbox to order' : goal === 'lead' ? 'Leave your contact' : 'Learn more';
const specs = [
  { key: 'campaign_angle_offer', title: 'Campaign Angle & Offer Draft',  focus: 'Positioning & offer',      objective: 'Define the core campaign angle and the offer to test' },
  { key: 'ad_copy_variants',     title: 'Ad Copy Variants Draft',        focus: 'Primary text & headlines', objective: 'Draft multiple ad copy variants for the owner to A/B test' },
  { key: 'audience_targeting',   title: 'Audience & Targeting Notes',    focus: 'Audience strategy',        objective: 'Outline audience segments & targeting notes (no audiences are created)' },
  { key: 'budget_testing_plan',  title: 'Budget & Testing Plan Draft',   focus: 'Budget & test structure',  objective: 'Draft a budget split and testing plan for owner review (no budget is set or spent)' },
  { key: 'ads_manager_handoff',  title: 'Ads Manager Handoff Checklist', focus: 'Manual handoff',           objective: 'Checklist for a human to set up manually in Ads Manager after approval' }
];
const items = specs.map((spec) => ({
  key: spec.key,
  title: spec.title,
  focus: spec.focus,
  objective: spec.objective,
  target_audience: audience,
  draft_body: `Draft notes for ${brand} (${product}) on ${channel}. ${spec.objective}. Offer to test: ${offer}. Draft only - no ads are created or launched.`,
  key_points: `Key draft points for ${brand} (${spec.focus}). Owner reviews and decides.`,
  testing_note: spec.key === 'budget_testing_plan' ? 'Draft only: small test budget split for owner review. No budget is set, scheduled, or spent.' : 'Draft note for owner review - nothing is created, launched, or scheduled.',
  cta,
  generated_by: 'n8n-ai-provider',
  workflow_type: 'ads_pack',
  content_type: 'ads_draft',
  status: 'pending_approval',
  owner_approval_required: true
}));
return [{ json: {
  ok: true,
  request_id: request.request_id,
  workflow_type: 'ads_pack',
  content_type: 'ads_draft',
  generated_by: 'n8n-ai-provider',
  owner_approval_required: true,
  status: 'pending_approval',
  job: {
    external_execution_id: $execution.id,
    item_count: items.length
  },
  items,
  safety: request.safety
}}];
